import { NextResponse } from 'next/server'
import bcrypt from 'bcryptjs'
import { getUsers, addUser } from '@/lib/auth'

export async function POST(request) {
  try {
    const body = await request.json()
    const { name, mobile, email, password } = body

    if (!name || !mobile || !email || !password) {
      return NextResponse.json({ error: 'Missing required fields' }, { status: 400 })
    }

    // Password strength validation
    const isStrong = /^(?=.*[A-Z])(?=.*\d)(?=.*[!@#$%^&*()_+])[A-Za-z\d!@#$%^&*()_+]{8,}$/.test(password)
    if (!isStrong) {
      return NextResponse.json({ 
        error: 'Password must be at least 8 characters, include an uppercase letter, a number, and a special symbol.' 
      }, { status: 400 })
    }

    const users = getUsers()
    const existingUser = users.find(u => u.mobile === mobile || u.email === email)
    if (existingUser) {
      return NextResponse.json({ error: 'User already exists' }, { status: 409 })
    }

    const passwordHash = await bcrypt.hash(password, 10)
    
    // Create actual user
    const newUser = {
      id: Date.now().toString(),
      name,
      mobile,
      email,
      passwordHash,
      role: 'Citizen', // Default role for registration
      failedAttempts: 0,
      lockedUntil: null
    }

    addUser(newUser)

    return NextResponse.json({ message: 'Registration successful via mock OTP verification' }, { status: 201 })
  } catch (error) {
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
  }
}
